def _extract_dbt_seed_attrs(attrs: DbtSeedAttributes) -> dict:
    """Extract all DbtSeed attributes from the attrs struct into a flat dict."""
    result = _extract_asset_attrs(attrs)
    result["dbt_seed_file_path"] = attrs.dbt_seed_file_path
    result["dbt_seed_stats"] = attrs.dbt_seed_stats
    result["dbt_alias"] = attrs.dbt_alias
    result["dbt_meta"] = attrs.dbt_meta
    result["dbt_unique_id"] = attrs.dbt_unique_id
    result["dbt_account_name"] = attrs.dbt_account_name
    result["dbt_project_name"] = attrs.dbt_project_name
    result["dbt_package_name"] = attrs.dbt_package_name
    result["dbt_job_name"] = attrs.dbt_job_name
    result["dbt_job_schedule"] = attrs.dbt_job_schedule
    result["dbt_job_status"] = attrs.dbt_job_status
    result["dbt_job_schedule_cron_humanized"] = attrs.dbt_job_schedule_cron_humanized
    result["dbt_job_last_run"] = attrs.dbt_job_last_run
    result["dbt_job_next_run"] = attrs.dbt_job_next_run
    result["dbt_job_next_run_humanized"] = attrs.dbt_job_next_run_humanized
    result["dbt_environment_name"] = attrs.dbt_environment_name
    result["dbt_environment_dbt_version"] = attrs.dbt_environment_dbt_version
    result["dbt_tags"] = attrs.dbt_tags
    result["dbt_connection_context"] = attrs.dbt_connection_context
    result["dbt_semantic_layer_proxy_url"] = attrs.dbt_semantic_layer_proxy_url
    result["dbt_job_runs"] = attrs.dbt_job_runs
    return result


