# CONVERSION FUNCTIONS
# =============================================================================


def _dbt_seed_to_nested(dbt_seed: DbtSeed) -> DbtSeedNested:
    """Convert flat DbtSeed to nested format."""
    attrs = DbtSeedAttributes()
    _populate_dbt_seed_attrs(attrs, dbt_seed)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        dbt_seed, _DBT_SEED_REL_FIELDS, DbtSeedRelationshipAttributes
    )
    return DbtSeedNested(
        guid=dbt_seed.guid,
        type_name=dbt_seed.type_name,
        status=dbt_seed.status,
        version=dbt_seed.version,
        create_time=dbt_seed.create_time,
        update_time=dbt_seed.update_time,
        created_by=dbt_seed.created_by,
        updated_by=dbt_seed.updated_by,
        classifications=dbt_seed.classifications,
        classification_names=dbt_seed.classification_names,
        meanings=dbt_seed.meanings,
        labels=dbt_seed.labels,
        business_attributes=dbt_seed.business_attributes,
        custom_attributes=dbt_seed.custom_attributes,
        pending_tasks=dbt_seed.pending_tasks,
        proxy=dbt_seed.proxy,
        is_incomplete=dbt_seed.is_incomplete,
        provenance_type=dbt_seed.provenance_type,
        home_id=dbt_seed.home_id,
        depth=dbt_seed.depth,
        immediate_upstream=dbt_seed.immediate_upstream,
        immediate_downstream=dbt_seed.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _dbt_seed_from_nested(nested: DbtSeedNested) -> DbtSeed:
    """Convert nested format to flat DbtSeed."""
    attrs = nested.attributes if nested.attributes is not UNSET else DbtSeedAttributes()
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DBT_SEED_REL_FIELDS,
        DbtSeedRelationshipAttributes,
    )
    return DbtSeed(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_dbt_seed_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _dbt_seed_to_nested_bytes(dbt_seed: DbtSeed, serde: Serde) -> bytes:
    """Convert flat DbtSeed to nested JSON bytes."""
    return serde.encode(_dbt_seed_to_nested(dbt_seed))


def _dbt_seed_from_nested_bytes(data: bytes, serde: Serde) -> DbtSeed:
    """Convert nested JSON bytes to flat DbtSeed."""
    nested = serde.decode(data, DbtSeedNested)
    return _dbt_seed_from_nested(nested)


